mapper.update:
UPDATE SHOP_CART
SET
    CART_CNT = CART_CNT + #{cartCnt}
    , TOTAL_PRICE = (
        (
            SELECT PRICE
            FROM ITEM
            WHERE ITEM_NUM = #{itemNum}
        ) * #{cartCnt}
    )
WHERE MEM_ID = #{memId}
AND ITEM_NUM = #{itemNum}

UPDATE shop_cart
SET
    CART_CNT = #{cartCnt}
    , TOTAL_PRICE = (SELECT PRICE
                    FROM ITEM
                    WHERE ITEM_NUM = #{itemNum}
                    ) * CART_CNT
WHERE MEM_ID = #{memId}
AND ITEM_NUM = #{itemNum}

